function [cntX,cntY] = fImgCntrd(img,vargin)%% return image centroid% [cntX,cntY] = fImgCntrd(img,vargin)% cntX: centroid X [pixel]% cntY: centroid Y [pixel]% % img: input image% vargin{1}: threshold%%% Written by Kei Nakamura% 2016/1/7 ver.1: created% %% internal constif nargin>1    threshold = vargin{1};else    threshold = 0;end%% get centroidimg = img.*(img>threshold);  % thresholding[sizeY,sizeX] = size(img);  % image sizexPrf = sum(img);    % x profile, integrated in yyPrf = sum(img,2);  % y profile, integrated in x[~,cntX] = fGetRmsV01(1:sizeX,xPrf);  % centroid x[~,cntY] = fGetRmsV01(1:sizeY,yPrf');  % centroid ycntX = round(cntX); cntY = round(cntY);
